/* ~/.config/nwg-drawer/drawer.css */

/* Target the top-level window */
window {
    background-color: transparent; /* Makes the "extra" fullscreen area invisible */
}

/* Target the actual visual box of the drawer */
#main-box {
    background-color: #000000; /* OLED Black to match your Waybar */
    border: 2px solid #45475a;
    border-radius: 24px;

    /* Force the 600x600 size */
    min-width: 600px;
    max-width: 600px;
    min-height: 600px;
    max-height: 600px;

    /* Center it manually if margins in the command don't work */
    margin: auto; 
    padding: 20px;
}

/* Make the search bar look like your Waybar pills */
#entry {
    background-color: #2b2b36;
    border-radius: 50px;
    margin: 10px 40px;
    padding: 8px 15px;
    border: 1px solid rgba(255, 255, 255, 0.1);
}

#app-grid {
    margin-top: 10px;
}

/* ~/.config/nwg-drawer/drawer.css */

window {
    background-color: rgba(0, 0, 0, 0.9); /* Pure OLED Black */
    border: 1px solid #45475a;
    border-radius: 20px;
}

/* This container holds the search bar and the app grid */
#main-box {
    margin: 100px; /* Increase margins to "shrink" the inner content area */
    background: #1e1e2e;
    border-radius: 15px;
    /* Manually limiting the size via CSS */
    min-width: 600px;
    max-width: 600px;
    min-height: 600px;
    max-height: 600px;
}

#entry {
    margin: 10px 40px; /* Pushes search bar in */
}

#app-grid {
    padding: 20px;
}

/* Example drawer.css */
window {
    background-color: rgba(0, 0, 0, 0.8); /* Dark OLED background */
}

#entry {
    background-color: #2b2b36;
    border-radius: 20px;
    margin: 20px;
    padding: 10px;
}

#pinned-box {
    padding: 10px;
}

#category-button {
    padding: 5px;
}

/* Power bar at the bottom */
#exit-button, #lock-button, #reboot-button, #suspend-button, #poweroff-button {
    margin: 10px;
    padding: 10px;
}

/* -----------------------------------------------------
 * GLOBAL RESET
 * ----------------------------------------------------- */
* {
    font-family: "JetBrainsMono Nerd Font", sans-serif;
    font-size: 14px;
    border: none;
    border-radius: 0;
    margin: 0;
    padding: 0;
    /* Removed min-height: 0; so containers stop collapsing */
}

window#waybar {
    background: transparent;
}

/* -----------------------------------------------------
 * OUTER PILLS (The Black OLED Shell)
 * ----------------------------------------------------- */
.modules-left,
.modules-center,
.modules-right {
    background-color: #000000; /* Pure OLED Black */
    border-radius: 50px;
    padding: 6px 8px;
    margin: 4px 6px;
}

/* -----------------------------------------------------
 * INNER PILLS (The Secondary Layer)
 * ----------------------------------------------------- */
.modules-left > widget > *,
.modules-center > widget > *,
.modules-right > widget > * {
    background-color: #2b2b36; 
    color: #cdd6f4;
    border-radius: 50px;
    padding: 2px 14px; /* Reduced vertical padding slightly to balance height */
    margin: 0 4px;
    min-height: 26px; /* THIS IS THE FIX: Forces every pill to be uniformly tall */
    transition: all 0.3s ease;
}

/* -----------------------------------------------------
 * DRAWER & GROUP DE-COMPRESSION
 * Prevents icons/text from overlapping inside the groups
 * ----------------------------------------------------- */
.modules-right .group label,
.modules-right .group > box > widget {
    margin: 0 6px;
}

.modules-right .group label:first-child,
.modules-right .group > box > widget:first-child {
    margin-left: 0;
}
.modules-right .group label:last-child,
.modules-right .group > box > widget:last-child {
    margin-right: 0;
}

.modules-right .group > box > widget > * {
    background-color: transparent;
}

/* -----------------------------------------------------
 * HOVER EFFECTS
 * ----------------------------------------------------- */
.modules-left > widget > *:hover,
.modules-center > widget > *:hover,
.modules-right > widget > *:hover {
    background-color: #45475a; 
}

/* -----------------------------------------------------
 * SPECIFIC COMPONENT COLORS & TWEAKS
 * ----------------------------------------------------- */
/* Arch Launcher */
#custom-launcher { color: #89b4fa; font-size: 16px; }

/* Paru Updater */
#custom-paru { color: #a6e3a1; }

/* Niri Workspaces */
#workspaces button {
    color: #a6adc8;
    background: transparent;
    padding: 0 6px;
    transition: all 0.2s ease;
}
#workspaces button.active {
    color: #a6e3a1; 
    font-weight: bold;
}
#workspaces button:hover {
    box-shadow: inherit;
    text-shadow: inherit;
    color: #cdd6f4;
}

/* WLR Taskbar (Middle App Icons) */
#taskbar button { background: transparent; padding: 0 6px; }
#taskbar button.active { background-color: #45475a; border-radius: 50px; }
#taskbar button:hover { background-color: #585b70; border-radius: 50px; }

/* Idle Inhibitor (Caffeine) */
#idle_inhibitor.activated { color: #f9e2af; }

/* Privacy Indicator */
#privacy { color: #f38ba8; }

/* Wlogout Power Button */
#custom-wlogout {
    color: #f38ba8;
    padding-left: 16px;
    padding-right: 16px;
}

/* -----------------------------------------------------
 * DYNAMIC HARDWARE COLORS (Warnings & Criticals)
 * ----------------------------------------------------- */
#cpu.warning, #memory.warning, #temperature.warning, #disk.warning, #battery.warning {
    color: #f9e2af;
}

#cpu.critical, #memory.critical, #temperature.critical, #disk.critical, #battery.critical {
    color: #f38ba8;
}

#battery.charging, #battery.plugged {
    color: #a6e3a1;
}

/* -----------------------------------------------------
 * GLOBAL RESET
 * Strips away the system GTK theme interference
 * ----------------------------------------------------- */
* {
    font-family: "JetBrainsMono Nerd Font", sans-serif;
    font-size: 14px;
    border: none;
    border-radius: 0;
    margin: 0;
    padding: 0;
    box-shadow: none;
    text-shadow: none;
}

window#waybar {
    background: transparent;
}

/* -----------------------------------------------------
 * 1. OUTER PILLS (The Black OLED Shell)
 * ----------------------------------------------------- */
.modules-left,
.modules-center,
.modules-right {
    background-color: #000000;
    border-radius: 50px;
    padding: 6px 8px; /* Creates the outer black rim */
    margin: 4px 6px;
}

/* -----------------------------------------------------
 * 2. INNER PILL BACKGROUNDS
 * Explicitly targeting your config's IDs so the background
 * applies to the correct wrapper, not the inner text.
 * ----------------------------------------------------- */
#custom-launcher,
#custom-paru,
#workspaces,
#clock,
#taskbar,
#privacy,
#idle_inhibitor,
#group-ppd-scx,
#group-amd-cpu-temp-ram,
#group-amd-gpu-vram-temp,
#group-nvme,
#group-network-speed,
#group-backlight-nightlight-volume,
#group-battery-power,
#bluetooth,
#custom-wlogout {
    background-color: #2b2b36;
    color: #cdd6f4;
    border-radius: 50px;
    padding: 0 14px; /* Horizontal padding only */
    margin: 0 4px;   /* Space between the grey pills */
}

/* -----------------------------------------------------
 * 3. THE HEIGHT FIX (The crucial part)
 * Forces labels (text) and buttons (clickable icons) 
 * to be the exact same height, eliminating the "cut off" look.
 * ----------------------------------------------------- */
label, button {
    padding-top: 4px;
    padding-bottom: 4px;
    min-height: 24px;
}

/* -----------------------------------------------------
 * 4. DRAWER & GROUP DE-COMPRESSION
 * Fixes the overlapping text inside your right-side groups
 * ----------------------------------------------------- */
.group widget {
    margin: 0 4px;
}
.group widget:first-child { margin-left: 0; }
.group widget:last-child { margin-right: 0; }

/* Ensure items inside groups don't draw a second background layer */
.group > box > widget {
    background-color: transparent;
}

/* -----------------------------------------------------
 * 5. COMPONENT COLORS & HOVER EFFECTS
 * ----------------------------------------------------- */
#custom-launcher { color: #89b4fa; font-size: 16px; }
#custom-paru { color: #a6e3a1; }
#idle_inhibitor.activated { color: #f9e2af; }
#privacy { color: #f38ba8; }
#custom-wlogout { color: #f38ba8; }

/* Workspaces */
#workspaces button { padding: 4px 6px; color: #a6adc8; background: transparent; }
#workspaces button.active { color: #a6e3a1; font-weight: bold; }

/* Middle Taskbar Apps */
#taskbar button { padding: 4px 6px; background: transparent; }
#taskbar button.active { background-color: #45475a; border-radius: 50px; }

/* Hover animations */
#custom-launcher:hover, #custom-paru:hover, #workspaces button:hover,
#taskbar button:hover, #bluetooth:hover, #custom-wlogout:hover, .group:hover {
    background-color: #45475a;
    border-radius: 50px;
    transition: all 0.2s ease;
}

/* -----------------------------------------------------
 * 6. DYNAMIC HARDWARE COLORS
 * ----------------------------------------------------- */
#cpu.warning, #memory.warning, #temperature.warning, #disk.warning, #battery.warning { color: #f9e2af; }
#cpu.critical, #memory.critical, #temperature.critical, #disk.critical, #battery.critical { color: #f38ba8; }
#battery.charging, #battery.plugged { color: #a6e3a1; }

/* =========================================
   Catppuccin Mocha Palette
   ========================================= */
@define-color base      #1e1e2e;
@define-color mantle    #181825;
@define-color crust     #11111b;
@define-color text      #cdd6f4;
@define-color subtext0  #a6adc8;
@define-color surface0  #313244;
@define-color surface1  #45475a;
@define-color surface2  #585b70;

@define-color blue      #89b4fa;
@define-color lavender  #b4befe;
@define-color sapphire  #74c7ec;
@define-color sky       #89dceb;
@define-color teal      #94e2d5;
@define-color green     #a6e3a1;
@define-color yellow    #f9e2af;
@define-color peach     #fab387;
@define-color maroon    #eba0ac;
@define-color red       #f38ba8;
@define-color mauve     #cba6f7;
@define-color pink      #f5c2e7;

/* =========================================
   Global & Window Settings
   ========================================= */
* {
    font-family: "JetBrainsMono Nerd Font", "Roboto", sans-serif;
    font-size: 14px;
    font-weight: 600;
    border: none;
    border-radius: 0;
    box-shadow: none;
    text-shadow: none;
    min-height: 0;
}

window {
    /* Slightly transparent mantle background for Wayland */
    background-color: alpha(@mantle, 0.85);
    border-bottom: 2px solid @surface0;
    color: @text;
}

/* Tooltips */
tooltip {
    background: @base;
    border: 1px solid @surface1;
    border-radius: 8px;
    color: @text;
}

/* =========================================
   Layout Containers (Left, Center, Right)
   ========================================= */
#start, #center, #end {
    margin: 4px;
    padding: 0 4px;
}

/* =========================================
   General Widget "Pill" Styling
   ========================================= */
.widget {
    background-color: @surface0;
    border-radius: 8px;
    padding: 0 10px;
    margin: 0 3px;
    color: @text;
    transition: background-color 0.2s ease;
}

.widget:hover {
    background-color: @surface1;
}

/* =========================================
   Specific Module Styling
   ========================================= */

/* Arch/Launcher Buttons */
.script:first-child {
    color: @blue;
    font-size: 16px;
    padding-right: 12px;
}

/* Niri Workspaces */
.workspaces {
    background-color: @surface0;
    border-radius: 8px;
    padding: 2px 4px;
    margin: 0 3px;
}

.workspaces button {
    color: @subtext0;
    background-color: transparent;
    border-radius: 6px;
    min-width: 24px;
    margin: 0 2px;
    padding: 0;
    transition: all 0.2s ease;
}

.workspaces button:hover {
    background-color: @surface1;
    color: @text;
}

.workspaces button.focused, 
.workspaces button.active {
    background-color: @surface2;
    color: @mauve;
    font-weight: 900;
}

/* Clock */
.clock {
    color: @lavender;
}

/* Wlr/Launcher Taskbar */
.launcher .item {
    margin: 0 4px;
    padding: 2px;
    border-radius: 6px;
}

.launcher .item:hover {
    background-color: @surface1;
}

.launcher .item.focused {
    background-color: @surface2;
    border-bottom: 2px solid @mauve;
}

/* System Info (CPU/RAM) */
.sys_info {
    color: @peach;
}

/* Network */
.network_manager {
    color: @teal;
}

/* Volume */
.volume {
    color: @sky;
}

/* Battery */
.battery {
    color: @green;
}

/* You can target states if Ironbar sets them (e.g., warning/critical) */
.battery.warning {
    color: @yellow;
}

.battery.critical {
    color: @red;
    animation: blink 1s linear infinite alternate;
}

@keyframes blink {
    0%   { opacity: 1; }
    100% { opacity: 0.4; }
}

/* Custom Scripts Highlighting (Matches grouped visual logic) */
/* The power menu button at the very end */
.script:last-child {
    color: @red;
    font-size: 16px;
    padding: 0 12px;
}

/* Catppuccin Mocha Palette */
@define-color base   #1e1e2e;
@define-color mantle #181825;
@define-color crust  #11111b;
@define-color text   #cdd6f4;
@define-color subtext0 #a6adc8;
@define-color surface0 #313244;
@define-color surface1 #45475a;
@define-color blue   #89b4fa;
